#include <stdio.h>
int main() {
    int T, n, m, start, end, arr[100005];
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &n, &m);
        for (int i = 0; i < n; i++) {
            scanf("%d", &arr[i]);
        }
        for (int i = 0; i < m; i++) {
            scanf("%d %d", &start, &end);
            int count = 0;
            for (int j = start - 1; j < end; j++) {
                count++;
            }
            printf("%d\n", count);
        }
    }
    return 0;
}

